CREATE TABLE technology_to_system
(
	id serial,
	technology_id integer NOT NULL,
	system_id integer DEFAULT NULL,
	CONSTRAINT pk_technology_to_system PRIMARY KEY (id)
	, CONSTRAINT fk_technology_to_system_to_technology FOREIGN KEY (technology_id) REFERENCES technologies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_technology_to_system_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_technology_to_system_technology ON technology_to_system (technology_id);
CREATE INDEX i_technology_to_system_system ON technology_to_system (system_id);
